const raw = $input.first().json.output[0].content[0].text;

// 🧹 Step 1: Clean markdown formatting (```json ... ```)
let cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// 🛠 Step 2: Try parsing safely
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    score: 50,
    category: "Warm",
    summary: cleaned
  };
}

// 🧪 Step 3: Extra safety (edge cases)
const score = typeof parsed.score === "number" ? parsed.score : 50;
const category = ["Hot", "Warm", "Cold"].includes(parsed.category)
  ? parsed.category
  : "Warm";
const summary = parsed.summary || "No summary available";

// 🚀 Final output
return [{
  json: {
    ...$json,
    leadScore: score,
    category: category,
    summary: summary
  }
}];

